import { test, expect, afterAll } from "vitest";
import { createServer } from "./server.ts";

const server = createServer().listen(0);
const base = await new Promise<string>((resolve) => {
  server.on("listening", () => {
    const addr = server.address();
    resolve(`http://127.0.0.1:${typeof addr === "object" && addr ? addr.port : 0}`);
  });
});
afterAll(() => server.close());

test("GET /users/:id returns the matching user", async () => {
  const res = await fetch(`${base}/users/1`);
  expect(res.status).toBe(200);
  expect(res.headers.get("content-type")).toBe("application/json");
  expect(await res.json()).toEqual({ id: "1", name: "Ada" });
});

test("GET /users/:id 404s for an unknown id", async () => {
  const res = await fetch(`${base}/users/999`);
  expect(res.status).toBe(404);
  expect(await res.json()).toEqual({ error: "not found" });
});

